import{_ as t,o as a,c as r,S as i}from"./chunks/framework.DZlzLDBr.js";const u=JSON.parse('{"title":"Reading View","description":"","frontmatter":{},"headers":[],"relativePath":"Reading-View.md","filePath":"Reading-View.md","lastUpdated":null}'),n={name:"Reading-View.md"};function s(o,e,d,l,c,g){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="reading-view" tabindex="-1">Reading View <a class="header-anchor" href="#reading-view" aria-label="Permalink to &quot;Reading View&quot;">​</a></h1><p>Last modified: 16/02/2026</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Reading View controls how Sprout card blocks look in Obsidian reading mode.</p><p>It does not change card data. It only changes how cards are displayed while reading notes.</p><h2 id="what-s-shown-in-reading-view" tabindex="-1">What&#39;s shown in reading view <a class="header-anchor" href="#what-s-shown-in-reading-view" aria-label="Permalink to &quot;What&#39;s shown in reading view&quot;">​</a></h2><p>In reading mode, Sprout can show:</p><ul><li>Card type badge (Basic, Cloze, MCQ, IO, Ordered).</li><li>Formatted card fields.</li><li>Edit button for quick edits.</li><li>Group tags.</li></ul><h2 id="appearance-settings" tabindex="-1">Appearance settings <a class="header-anchor" href="#appearance-settings" aria-label="Permalink to &quot;Appearance settings&quot;">​</a></h2><p>Change these in <strong>Settings → Reading</strong>:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td><strong>Enable card styling</strong></td><td>When off, cards use native Obsidian reading view with no Sprout styling</td></tr><tr><td><strong>Macro styles</strong></td><td>Currently available: Disabled, Flashcards, and Clean markdown. More styles are planned for a future update</td></tr><tr><td><strong>Reading view fields</strong></td><td>Configure visible fields per macro style</td></tr><tr><td><strong>Reading view colours</strong></td><td>Customise card colours for styles that support colour settings</td></tr><tr><td><strong>Custom style CSS</strong></td><td>Reserved for the future Custom style (not active yet)</td></tr></tbody></table><h2 id="macro-styles" tabindex="-1">Macro styles <a class="header-anchor" href="#macro-styles" aria-label="Permalink to &quot;Macro styles&quot;">​</a></h2><ul><li><strong>Disabled</strong>: Uses native Obsidian reading rendering with Sprout card styling turned off.</li><li><strong>Flashcards</strong>: Front/back flip cards (question on front, answer on back).</li><li><strong>Clean markdown</strong>: Minimal, tidied markdown-style card rendering.</li></ul><p>Planned for a future release: <strong>Classic</strong>, <strong>Guidebook</strong>, and <strong>Custom</strong>.</p><p>For details, see <a href="./Reading-View-Styles">Reading View Styles</a> and <a href="./Custom-Reading-Styles">Custom Reading Styles</a>.</p><h2 id="interaction" tabindex="-1">Interaction <a class="header-anchor" href="#interaction" aria-label="Permalink to &quot;Interaction&quot;">​</a></h2><ul><li><strong>Edit button</strong> opens the card editor for that card.</li><li>Cloze cards can show hints or blanks, based on your settings.</li><li>Embedded images render inline.</li><li>Math uses Obsidian LaTeX rendering.</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Use Reading View to spot formatting problems before studying.</li><li>If a card looks wrong, use Edit directly from the card block.</li><li>If a card block does not render as expected, check card syntax and run a sync.</li></ul>',19)])])}const p=t(n,[["render",s]]);export{u as __pageData,p as default};
